	m.HandleFunc("POST "+options.BaseURL+"/admin/users/{userId}/deactivate", wrapper.DeactivateAdminUser)
	m.HandleFunc("POST "+options.BaseURL+"/admin/users/{userId}/reactivate", wrapper.ReactivateAdminUser)
